// Simple property decorator that records min/max constraints
const CONSTRAINTS_KEY = Symbol('constraints');

function Min(min: number) {
  return (target: object, propertyKey: string | symbol): void => {
    const existing: Record<string, number> =
      Reflect.getMetadata(CONSTRAINTS_KEY, target, propertyKey) ?? {};
    Reflect.defineMetadata(CONSTRAINTS_KEY, { ...existing, min }, target, propertyKey);
  };
}

function Max(max: number) {
  return (target: object, propertyKey: string | symbol): void => {
    const existing: Record<string, number> =
      Reflect.getMetadata(CONSTRAINTS_KEY, target, propertyKey) ?? {};
    Reflect.defineMetadata(CONSTRAINTS_KEY, { ...existing, max }, target, propertyKey);
  };
}

class Order {
  @Min(1) @Max(100)
  quantity = 1;
}

// Retrieve at runtime:
const qMeta = Reflect.getMetadata(CONSTRAINTS_KEY, Order.prototype, 'quantity');
console.log(qMeta); // { min: 1, max: 100 }

@Component({ selector: 'app-button', template: '<button (click)="clicked.emit()">{{ label }}</button>' })
export class ButtonComponent {
  @Input() label = 'Click me';
  @Input({ required: true }) type!: 'button' | 'submit' | 'reset';

  @Output() clicked = new EventEmitter<void>();
  @Output('pressed') pressed = new EventEmitter<void>(); // alias
}

// Method decorator that logs call duration
function Measure(target: object, key: string | symbol, descriptor: PropertyDescriptor): PropertyDescriptor {
  const original = descriptor.value as (...args: unknown[]) => unknown;

  descriptor.value = function (...args: unknown[]) {
    const start = performance.now();
    const result = original.apply(this, args);
    const ms = (performance.now() - start).toFixed(2);
    console.log(\`\${String(key)}: \${ms}ms\`);
    return result;
  };

  return descriptor;
}

class DataService {
  @Measure
  processLargeDataset(data: number[]): number {
    return data.reduce((sum, n) => sum + n, 0);
  }
}

const svc = new DataService();
svc.processLargeDataset(Array.from({ length: 100000 }, (_, i) => i));
// Console: processLargeDataset: 4.20ms

function Memoize(target: object, key: string | symbol, descriptor: PropertyDescriptor): PropertyDescriptor {
  const original = descriptor.value as (...args: unknown[]) => unknown;
  const cache = new Map<string, unknown>();

  descriptor.value = function (...args: unknown[]) {
    const cacheKey = JSON.stringify(args);
    if (cache.has(cacheKey)) return cache.get(cacheKey);
    const result = original.apply(this, args);
    cache.set(cacheKey, result);
    return result;
  };

  return descriptor;
}

class PricingEngine {
  @Memoize
  calculateDiscount(price: number, tier: string): number {
    // Expensive computation — only runs once per (price, tier) pair
    const rate = tier === 'premium' ? 0.2 : 0.1;
    return price * (1 - rate);
  }
}

function Bind(target: object, key: string | symbol, descriptor: PropertyDescriptor): PropertyDescriptor {
  return {
    configurable: true,
    get(this: object) {
      const bound = descriptor.value.bind(this);
      Object.defineProperty(this, key, { value: bound, configurable: true, writable: true });
      return bound;
    }
  };
}

class Counter {
  count = 0;

  @Bind
  increment() { this.count++; }
}

const c = new Counter();
const { increment } = c; // destructuring normally loses 'this'
increment();             // OK — @Bind fixes it
console.log(c.count);   // 1

function Debounce(ms: number) {
  return (target: object, key: string | symbol, descriptor: PropertyDescriptor): PropertyDescriptor => {
    const original = descriptor.value as (...args: unknown[]) => void;
    let timer: ReturnType<typeof setTimeout> | null = null;

    descriptor.value = function (...args: unknown[]) {
      if (timer !== null) clearTimeout(timer);
      timer = setTimeout(() => original.apply(this, args), ms);
    };

    return descriptor;
  };
}

class SearchComponent {
  @Debounce(300)
  onSearch(term: string): void {
    // Called at most once per 300ms of quiet
    console.log('Searching for:', term);
  }
}

@Directive({ selector: '[appHighlight]', standalone: true })
export class HighlightDirective {
  constructor(private el: ElementRef<HTMLElement>) {}

  @HostListener('mouseenter')
  onMouseEnter(): void {
    this.el.nativeElement.style.background = 'yellow';
  }

  @HostListener('mouseleave')
  onMouseLeave(): void {
    this.el.nativeElement.style.background = '';
  }

  // $event is passed through by Angular
  @HostListener('click', ['$event'])
  onClick(event: MouseEvent): void {
    console.log('Clicked at', event.clientX, event.clientY);
  }
}

function Clamp(min: number, max: number) {
  return (target: object, key: string | symbol, descriptor: PropertyDescriptor): PropertyDescriptor => {
    const originalSet = descriptor.set;
    if (!originalSet) throw new Error('@Clamp requires a setter');

    descriptor.set = function (value: number) {
      originalSet.call(this, Math.min(max, Math.max(min, value)));
    };

    return descriptor;
  };
}

class Slider {
  private _value = 0;

  @Clamp(0, 100)
  get value() { return this._value; }
  set value(v: number) { this._value = v; }
}

const s = new Slider();
s.value = 150; // clamped to 100
s.value = -10; // clamped to 0
console.log(s.value); // 0

const RULES_KEY = Symbol('rules');

type Rule = (value: unknown) => string | null; // returns error or null

function Rule(rule: Rule) {
  return (target: object, key: string | symbol) => {
    const existing: Rule[] = Reflect.getMetadata(RULES_KEY, target, key) ?? [];
    Reflect.defineMetadata(RULES_KEY, [...existing, rule], target, key);
  };
}

// Pre-built rule factories
const required: Rule = v => (v == null || v === '' ? 'Required' : null);
const minLength = (n: number): Rule => v =>
  typeof v === 'string' && v.length < n ? \`Min \${n} chars\` : null;

// Method decorator that validates all decorated properties
function Validate(target: object, key: string | symbol, descriptor: PropertyDescriptor): PropertyDescriptor {
  const original = descriptor.value as (this: Record<string, unknown>) => void;

  descriptor.value = function (this: Record<string, unknown>) {
    const errors: string[] = [];

    for (const prop of Object.keys(this)) {
      const rules: Rule[] = Reflect.getMetadata(RULES_KEY, target, prop) ?? [];
      for (const rule of rules) {
        const err = rule(this[prop]);
        if (err) errors.push(\`\${prop}: \${err}\`);
      }
    }

    if (errors.length) throw new Error(\`Validation failed:\n\${errors.join('\n')}\`);
    return original.call(this);
  };

  return descriptor;
}

// Usage
class RegistrationForm {
  @Rule(required) @Rule(minLength(3)) username = '';
  @Rule(required) email = '';

  @Validate
  submit(): void {
    console.log('Form submitted', this.username, this.email);
  }
}

const form = new RegistrationForm();
// form.submit(); // Error: Validation failed
username: Required
email: Required
form.username = 'alice';
form.email = 'alice@example.com';
form.submit(); // 'Form submitted alice alice@example.com'

const PARAM_META = Symbol('paramMeta');

function LogParam(target: object, methodKey: string | symbol, paramIndex: number): void {
  const existing: number[] = Reflect.getMetadata(PARAM_META, target, methodKey) ?? [];
  Reflect.defineMetadata(PARAM_META, [...existing, paramIndex], target, methodKey);
}

class OrderService {
  processOrder(@LogParam orderId: string, @LogParam amount: number): void {
    // Angular uses a similar mechanism to find which constructor param
    // to inject when the type can't be inferred
  }
}

const tracked: number[] = Reflect.getMetadata(PARAM_META, OrderService.prototype, 'processOrder') ?? [];
console.log(tracked); // [0, 1] — indices of the decorated params

// Angular @Inject example
@Injectable()
class AnalyticsService {
  constructor(@Inject(ANALYTICS_URL) private url: string) {}
}

describe('@Min / @Max decorators', () => {
  it('records min constraint on the property', () => {
    class Dto {
      @Min(1) quantity = 0;
    }

    const meta = Reflect.getMetadata(CONSTRAINTS_KEY, Dto.prototype, 'quantity');
    expect(meta.min).toBe(1);
  });

  it('records max constraint stacked on top of min', () => {
    class Dto {
      @Min(1) @Max(99) quantity = 0;
    }

    const meta = Reflect.getMetadata(CONSTRAINTS_KEY, Dto.prototype, 'quantity');
    expect(meta.min).toBe(1);
    expect(meta.max).toBe(99);
  });
});

describe('@Debounce decorator', () => {
  beforeEach(() => jasmine.clock().install());
  afterEach(() => jasmine.clock().uninstall());

  it('delays the call by the specified ms', () => {
    const spy = jasmine.createSpy('handler');

    class Widget {
      @Debounce(200)
      onInput(): void { spy(); }
    }

    const w = new Widget();
    w.onInput();
    w.onInput();
    w.onInput();

    expect(spy).not.toHaveBeenCalled(); // not yet
    jasmine.clock().tick(200);
    expect(spy).toHaveBeenCalledOnceWith(); // called exactly once
  });
});

describe('@Memoize decorator', () => {
  it('calls the original only once for the same args', () => {
    const compute = jasmine.createSpy('compute').and.returnValue(42);

    class Calc {
      @Memoize
      run(x: number) { return compute(x); }
    }

    const c = new Calc();
    c.run(5);
    c.run(5);
    c.run(5);
    expect(compute).toHaveBeenCalledTimes(1);
  });
});

function ClassDec(target: Function) { console.log('class'); }
function PropDec(t: object, k: string | symbol) { console.log(\`prop: \${String(k)}\`); }
function MethodDec(t: object, k: string | symbol, d: PropertyDescriptor) { console.log(\`method: \${String(k)}\`); }

@ClassDec
class Demo {
  @PropDec name = 'hello';

  @MethodDec
  greet() {}
}

// Output order:
// prop: name
// method: greet
// class
